# ---------------------------------------------------------------------------
# SVG generation and caching
# ---------------------------------------------------------------------------

_SVG_CACHE: dict[str, str] = {}


def _build_svg(slug: str) -> str | None:
    """Build a complete SVG string for the given icon slug."""
    if slug not in _ICON_PATHS:
        return None
    color, path_d = _ICON_PATHS[slug]
    return (
        f'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">'
        f'<path d="{path_d}" fill="#{color}"/>'
        f'</svg>'
    )


def _resolve_slug(label: str, component_type: str | None = None) -> str | None:
    """Find the icon slug for a component by type or label."""
    if component_type:
        key = component_type.lower().strip()
        if key in _COMPONENT_TO_ICON:
            return _COMPONENT_TO_ICON[key]
    # Try label tokens
    for token in label.lower().split():
        if token in _COMPONENT_TO_ICON:
            return _COMPONENT_TO_ICON[token]
    # Substring match
    label_lower = label.lower()
    for key, slug in _COMPONENT_TO_ICON.items():
        if key in label_lower:
            return slug
    return None


def has_icon(label: str, component_type: str | None = None) -> bool:
    """Check whether a component has an associated icon."""
    return _resolve_slug(label, component_type) is not None


def get_icon_data_url(label: str, component_type: str | None = None) -> str | None:
    """Return a base64 data URL for the component icon, or None."""
    slug = _resolve_slug(label, component_type)
    if slug is None:
        return None
    if slug in _SVG_CACHE:
        return _SVG_CACHE[slug]
    svg = _build_svg(slug)
    if svg is None:
        return None
    b64 = base64.b64encode(svg.encode("utf-8")).decode("ascii")
    data_url = f"data:image/svg+xml;base64,{b64}"
    _SVG_CACHE[slug] = data_url
    return data_url
